// // This module implements a 2-bit Johnson counter that toggles bits in reverse order and resets to '11' on reset.
module johnson_counter(
    input clk,
    input reset,
    output reg [1:0] q);

    always @(posedge clk) begin
        if (reset) begin
            q <= 2'b00;
        end else begin
            q <= {q[0], ~q[1]};
        end
    end

endmodule
